class SharedToolbar {
  private static instances = new WeakMap<HTMLElement, SharedToolbar>();

  static get(container: HTMLElement) {
    let toolbar = this.instances.get(container);
    if (toolbar == null) {
      toolbar = new SharedToolbar(container);
      this.instances.set(container, toolbar);
    }
    return toolbar;
  }

  readonly toolbars = new Set<Toolbar>();
  readonly controls = new Map<HTMLElement, string>();
  active?: Toolbar;
  private observer: MutationObserver;

  private constructor(readonly container: HTMLElement) {
    this.observer = new MutationObserver(() => this.reconcile());
    this.observer.observe(document.body, { childList: true, subtree: true });
    this.reconcile();
  }

  add(toolbar: Toolbar) {
    this.toolbars.add(toolbar);
    this.reconcile();
  }

  activate(toolbar: Toolbar) {
    this.removeDead();
    if (!this.toolbars.has(toolbar)) return;
    this.active = toolbar;
    this.update();
  }

  getActive() {
    this.removeDead();
    return this.active;
  }

  private removeDead() {
    Array.from(this.toolbars).forEach((toolbar) => {
      if (!document.body.contains(toolbar.quill.root)) {
        this.toolbars.delete(toolbar);
        if (this.active === toolbar) this.active = undefined;
      }
    });
    if (this.toolbars.size === 0) this.destroy();
  }

  private destroy() {
    this.controls.forEach((format, input) => {
      input.removeEventListener(input.tagName === 'SELECT' ? 'change' : 'click', this.handleControl);
    });
    this.controls.clear();
    this.observer.disconnect();
    this.container.querySelectorAll('.ql-picker').forEach((picker) => picker.remove());
    this.container.querySelectorAll('select').forEach((select) => {
      (select as HTMLElement).style.display = '';
    });
    this.container.querySelectorAll('input.ql-image[type=file]').forEach((input) => input.remove());
    this.container.dispatchEvent(new Event('ql-toolbar-destroy'));
    SharedToolbar.instances.delete(this.container);
  }

  private reconcile() {
    this.removeDead();
